script:
# NOT a standalone script — this is the body of a Server Script record
# (Script Type: DocType Event, Reference: LedgerLift, Event: Before Save).
# Runs in Frappe's restricted safe-exec sandbox; only whitelisted methods used
# (frappe.utils, frappe.db.get_value, frappe.get_all, frappe.throw, _).

# 1. Days Outstanding — authoritative server-side calculation.
if doc.oldest_invoice_date:
    doc.days_outstanding = frappe.utils.date_diff(frappe.utils.nowdate(), doc.oldest_invoice_date) or 0
else:
    doc.days_outstanding = 0

# 2. Lock records already marked Paid — only administrators may modify.
#    The form client script only disables the UI; this is the real enforcement
#    (covers REST API, bulk edit and data import paths too).
if not doc.is_new():
    previous_status = frappe.db.get_value("LedgerLift Tracker", doc.name, "recovery_status")
    if previous_status == "Paid":
        user = frappe.session.user
        is_admin = user == "Administrator" or frappe.get_all(
            "Has Role",
            filters={"parent": user, "parenttype": "User", "role": "System Manager"},
            limit=1,
        )
        if not is_admin:
            frappe.throw(_("This LedgerLift record is marked Paid and locked. Only an administrator can modify it."))

# 3. Stamp / clear Paid On (drives the "Recovery This Month" number card).
if doc.recovery_status == "Paid" and not doc.paid_on:
    doc.paid_on = frappe.utils.nowdate()
if doc.recovery_status != "Paid" and doc.paid_on:
    doc.paid_on = None


# --- rolling follow-up sync (latest interaction row drives current next-action) ---
rows = doc.get("follow_ups") or []
if rows:
    last = None
    last_key = None
    for r in rows:
        key = (str(r.follow_up_date or "1900-01-01"), r.idx or 0)
        if last is None or key >= last_key:
            last = r
            last_key = key
    if last.follow_up_date:
        doc.last_contact_date = last.follow_up_date
    if last.next_follow_up_date:
        doc.next_follow_up_date = last.next_follow_up_date
    if last.promised_amount:
        doc.promised_amount = last.promised_amount
    if last.promised_date:
        doc.promised_payment_date = last.promised_date

count = frappe.db.count("LedgerLift Tracker", {
    "recovery_status": ["!=", "Paid"],
    "next_follow_up_date": ["<=", frappe.utils.nowdate()],
})
frappe.response["message"] = count

s = frappe.get_doc("StockPilot Settings")
if frappe.utils.cint(s.freeze_classes):
    months = frappe.utils.cint(s.class_freeze_months)
    if months < 1:
        months = 3
    refresh = 0
    if not s.frozen_on:
        refresh = 1
    elif frappe.utils.date_diff(frappe.utils.nowdate(), frappe.utils.add_months(s.frozen_on, months)) >= 0:
        refresh = 1
    if refresh:
        res = frappe.get_doc("Report", "StockPilot Categories").execute_script_report({"view": "raw"})
        mp = {}
        for r in res[1]:
            cc = (r.get("m") or "C") + (r.get("v") or "C")
            mp[r.get("code")] = [cc, frappe.utils.flt(r.get("a12"))]
        s.frozen_class_map = json.dumps(mp)
        s.frozen_on = frappe.utils.nowdate()
        s.save()

# Driver Slip guard rails (fixture; pairs with the /slip PWA)
# PLACES: keep in sync with "Driver Slip Bootstrap" — adding an origin means
# editing BOTH scripts (DB records, no deploy needed).
# NB safe_exec: no frappe.generate_hash / frappe.get_roles here.
PLACES = {
    "Main Store Paraswada (KP)": "Purchase",
    "Parijat (VAC)": "Sale",
    "VAC Main Store": "Sale",
    "Durgaurd Warehouse (VAC)": "Sale",
    "Mahabeej Warehouse (VAC)": "Sale",
}

leg = PLACES.get(doc.from_place or "")
if not leg:
    frappe.throw("Unknown From place: " + (doc.from_place or "(blank)"))
doc.direction = leg

if not doc.get("items"):
    frappe.throw("At least one goods line (मालाचे नाव + नग) is required")
parts = []
for row in doc.items:
    if not row.item:
        frappe.throw("Goods (मालाचे नाव) missing on row " + str(row.idx))
    if not row.qty or row.qty <= 0:
        frappe.throw("Bags (नग) must be more than zero — row " + str(row.idx))
    parts.append(row.item + " × " + frappe.utils.cstr(frappe.utils.flt(row.qty)))
doc.items_summary = ", ".join(parts)[:140]

if doc.slip_date and frappe.utils.getdate(doc.slip_date) > frappe.utils.add_days(frappe.utils.getdate(frappe.utils.today()), 1):
    frappe.throw("Slip date cannot be in the future")

if not doc.warehouse:
    doc.warehouse = "Main Store - VAC"

# idempotency key auto-fill for desk-entered slips (naming has already run)
if not doc.client_uid:
    doc.client_uid = "desk-" + (doc.name or "")

# lock after review: desk (System) users may still adjust; phone users may not
if not doc.is_new():
    old_status = frappe.db.get_value("Driver Slip", doc.name, "status")
    utype = frappe.db.get_value("User", frappe.session.user, "user_type")
    if old_status and old_status != "Pending Review" and utype != "System User":
        frappe.throw("This slip is already " + old_status + " — ask the office to change it")

# Idempotent slip insert for the /slip PWA (fixture; multi-item)
p = frappe.form_dict
uid = (p.get("client_uid") or "").strip()
if not uid:
    frappe.throw("client_uid required")

existing = frappe.db.get_value("Driver Slip", {"client_uid": uid}, "name")
if existing:
    frappe.response["message"] = {"name": existing, "created": 0}
else:
    items = p.get("items") or []
    if isinstance(items, str):
        items = frappe.parse_json(items)
    rows = []
    for it in items:
        rows.append({"item": it.get("item"), "qty": it.get("qty")})
    d = frappe.get_doc({
        "doctype": "Driver Slip",
        "client_uid": uid,
        "slip_date": p.get("slip_date"),
        "challan_no": p.get("challan_no"),
        "from_place": p.get("from_place"),
        "destination": p.get("destination"),
        "notes": p.get("notes"),
        "items": rows,
    })
    d.insert()
    frappe.response["message"] = {"name": d.name, "created": 1}

# App bootstrap for the /slip PWA: driver name + origin places + KP-trade
# shortlist + searchable item list (fixture).
# PLACES: keep in sync with "Driver Slip Validate" — adding an origin means
# editing BOTH scripts (DB records, no deploy needed).
PLACES = [
    {"value": "Main Store Paraswada (KP)", "label": "मेन स्टोअर परसवाडा", "hint": "प्लांटवरून माल आणला", "leg": "Purchase"},
    {"value": "Parijat (VAC)", "label": "परिजात", "hint": "गोदामातून माल नेला", "leg": "Sale"},
    {"value": "VAC Main Store", "label": "VAC दुकान", "hint": "दुकानातून माल नेला", "leg": "Sale"},
    {"value": "Durgaurd Warehouse (VAC)", "label": "दुर्गाउर्ड गोदाम", "hint": "गोदामातून माल नेला", "leg": "Sale"},
    {"value": "Mahabeej Warehouse (VAC)", "label": "महाबीज गोदाम", "hint": "गोदामातून माल नेला", "leg": "Sale"},
]

kp = "Krushiyog Plant, Paraswada"
si_names = frappe.get_all("Sales Invoice", filters={"customer": kp, "docstatus": ["<", 2]}, pluck="name", limit_page_length=300, order_by="posting_date desc")
pi_names = frappe.get_all("Purchase Invoice", filters={"supplier": kp, "docstatus": ["<", 2]}, pluck="name", limit_page_length=300, order_by="posting_date desc")

short = []
if pi_names:
    for r in frappe.get_all("Purchase Invoice Item", filters={"parent": ["in", pi_names]}, fields=["item_code"], limit_page_length=0):
        if r.item_code and r.item_code not in short:
            short.append(r.item_code)
if si_names:
    for r in frappe.get_all("Sales Invoice Item", filters={"parent": ["in", si_names]}, fields=["item_code"], limit_page_length=0):
        if r.item_code and r.item_code not in short:
            short.append(r.item_code)

items = frappe.get_all("Item", filters={"disabled": 0}, fields=["name", "item_name", "stock_uom"], limit_page_length=0, order_by="name")

frappe.response["message"] = {
    "driver": frappe.db.get_value("User", frappe.session.user, "full_name"),
    "places": PLACES,
    "shortlist": short,
    "items": items,
}
